const cfg = $('EVEZ Config').first().json;
const signals = { scanned_at: new Date().toISOString(), sources: [] };

// ── 1. CoinGecko: DeFi yields + trending ───────────────
try {
  const trending = await $fetch('https://api.coingecko.com/api/v3/search/trending');
  const defi = await $fetch('https://api.coingecko.com/api/v3/coins/markets?vs_currency=usd&category=decentralized-finance-defi&order=volume_desc&per_page=5&sparkline=false');
  signals.defi = {
    trending: (trending.coins || []).slice(0, 5).map(function(c) {
      return { name: c.item.name, symbol: c.item.symbol, rank: c.item.market_cap_rank };
    }),
    top_defi: (defi || []).slice(0, 5).map(function(c) {
      return { name: c.name, symbol: c.symbol, price_change_24h: c.price_change_percentage_24h };
    })
  };
  signals.sources.push('coingecko');
} catch(e) { signals.defi = { error: e.message }; }

// ── 2. Fear & Greed ─────────────────────────────────────
try {
  const fg = await $fetch('https://api.alternative.me/fng/?limit=3');
  signals.fear_greed = {
    now: { value: fg.data[0].value, label: fg.data[0].value_classification },
    yesterday: { value: fg.data[1].value, label: fg.data[1].value_classification },
    trend: parseInt(fg.data[0].value) - parseInt(fg.data[1].value)
  };
  signals.sources.push('fear_greed');
} catch(e) { signals.fear_greed = { error: e.message }; }

// ── 3. HackerNews: tech opportunities ──────────────────
try {
  const hn = await $fetch('https://hn.algolia.com/api/v1/search?query=AI+agent+automation+SaaS+revenue+2026&hitsPerPage=6&tags=story');
  signals.hackernews = (hn.hits || []).map(function(h) {
    return { title: (h.title || '').slice(0, 100), points: h.points, url: h.url };
  });
  signals.sources.push('hackernews');
} catch(e) { signals.hackernews = []; }

// ── 4. Reddit: community alpha ──────────────────────────
try {
  const subs = ['algotrading', 'defi', 'AutomateYourself', 'SideProject'];
  signals.reddit = [];
  for (var i = 0; i < subs.length; i++) {
    try {
      var r = await $fetch('https://www.reddit.com/r/' + subs[i] + '/hot.json?limit=3',
        { headers: { 'User-Agent': 'EVEZ-OS/1.0' } });
      var posts = (r.data.children || []).map(function(p) {
        return { title: (p.data.title || '').slice(0, 100), score: p.data.score, sub: subs[i] };
      });
      signals.reddit = signals.reddit.concat(posts);
    } catch(e2) {}
  }
  signals.reddit = signals.reddit.sort(function(a,b){ return b.score - a.score; }).slice(0, 8);
  signals.sources.push('reddit');
} catch(e) { signals.reddit = []; }

// ── 5. GitHub Trending: things to build on/with ─────────
try {
  const gh = await $fetch('https://api.github.com/search/repositories?q=AI+agent+autonomous+stars:>100&sort=stars&order=desc&per_page=5',
    { headers: { 'User-Agent': 'EVEZ-OS/1.0', 'Accept': 'application/vnd.github.v3+json' } });
  signals.github = (gh.items || []).map(function(r) {
    return { name: r.full_name, stars: r.stargazers_count, description: (r.description || '').slice(0, 80), language: r.language };
  });
  signals.sources.push('github');
} catch(e) { signals.github = []; }

// ── 6. DuckDuckGo: keyword intelligence ─────────────────
try {
  const queries = ['AI automation SaaS 2026', 'web3 grant funding open', 'autonomous agent monetization'];
  signals.ddg = [];
  for (var q = 0; q < queries.length; q++) {
    try {
      var d = await $fetch('https://api.duckduckgo.com/?q=' + encodeURIComponent(queries[q]) + '&format=json&no_html=1&skip_disambig=1',
        { headers: { 'User-Agent': 'EVEZ-OS/1.0' } });
      if (d.AbstractText) signals.ddg.push({ query: queries[q], abstract: d.AbstractText.slice(0, 200) });
    } catch(e3) {}
  }
  signals.sources.push('duckduckgo');
} catch(e) {}

// ── 7. Crypto grants / funding signals ──────────────────
try {
  // Gitcoin grants API (public)
  const gc = await $fetch('https://grants-stack-indexer-v2.gitcoin.co/graphql', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ query: '{ rounds(first: 5, orderBy: createdAtBlock, orderDirection: desc) { id roundMetadata { name description } matchAmountInUsd donationsCount } }' })
  });
  signals.grants = (gc.data && gc.data.rounds ? gc.data.rounds : []).map(function(r) {
    return { name: (r.roundMetadata && r.roundMetadata.name) || 'Unknown', match_usd: r.matchAmountInUsd, donations: r.donationsCount };
  });
  signals.sources.push('gitcoin');
} catch(e) { signals.grants = []; }

signals.slot = Math.floor(Date.now() / 21600000); // 6h slots
signals.sources_count = signals.sources.length;
return [{ json: signals }];

const cfg = $('EVEZ Config').first().json;
const signals = $('Opportunity Scanner').first().json;

async function llm(sys, usr) {
  if (cfg.groq_key) {
    try {
      var r = await $fetch('https://api.groq.com/openai/v1/chat/completions', {
        method: 'POST',
        headers: { 'Authorization': 'Bearer ' + cfg.groq_key, 'Content-Type': 'application/json' },
        body: JSON.stringify({ model: 'llama-3.3-70b-versatile', max_tokens: 3000,
          messages: [{ role: 'system', content: sys }, { role: 'user', content: usr }],
          temperature: 0.3 })
      });
      var t = r.choices[0].message.content;
      return JSON.parse(t.replace(/```json|```/g, '').trim());
    } catch(e) {}
  }
  if (cfg.gemini_key) {
    try {
      var r2 = await $fetch('https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=' + cfg.gemini_key, {
        method: 'POST', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ systemInstruction: { parts: [{ text: sys }] },
          contents: [{ role: 'user', parts: [{ text: usr }] }],
          generationConfig: { maxOutputTokens: 3000, temperature: 0.3 } })
      });
      var t2 = r2.candidates[0].content.parts[0].text;
      return JSON.parse(t2.replace(/```json|```/g, '').trim());
    } catch(e2) {}
  }
  if (cfg.or_key) {
    try {
      var r3 = await $fetch('https://openrouter.ai/api/v1/chat/completions', {
        method: 'POST',
        headers: { 'Authorization': 'Bearer ' + cfg.or_key, 'Content-Type': 'application/json', 'HTTP-Referer': 'https://evezos.app.n8n.cloud' },
        body: JSON.stringify({ model: 'meta-llama/llama-3.3-70b-instruct:free', max_tokens: 3000,
          messages: [{ role: 'system', content: sys }, { role: 'user', content: usr }] })
      });
      var t3 = r3.choices[0].message.content;
      return JSON.parse(t3.replace(/```json|```/g, '').trim());
    } catch(e3) {}
  }
  return { error: 'No AI provider. Set GROQ_API_KEY (free: console.groq.com)', agents: [] };
}

