const cfg = $('EVEZ Config').first().json;
const architect = $('AI Architect').first().json;

const agents = architect.agents || [];
const spawned = [];
const failed = [];

if (!cfg.n8n_key) {
  return [{ json: {
    spawned: [],
    failed: [{ reason: 'N8N_API_KEY not set. Go to n8n Settings → API → Create key → add as N8N_API_KEY env var.' }],
    note: 'Spawn engine ready — just needs N8N_API_KEY to create sub-workflows automatically.',
    ts: new Date().toISOString()
  }}];
}

for (var i = 0; i < agents.length; i++) {
  var agent = agents[i];
  if (!agent.workflow || !agent.workflow.nodes) {
    failed.push({ type: agent.type, reason: 'AI did not return valid workflow JSON' });
    continue;
  }

  try {
    // Ensure workflow has required fields
    var wf = agent.workflow;
    wf.settings = wf.settings || {};
    wf.settings.executionOrder = 'v1';
    wf.settings.availableInMCP = true;
    if (!wf.name || wf.name.includes('[')) {
      wf.name = 'SPAWN: ' + agent.type + ' [' + new Date().toISOString().slice(0, 10) + ']';
    }

    // Create via n8n API
    var created = await $fetch(cfg.n8n_base + '/api/v1/workflows', {
      method: 'POST',
      headers: { 'X-N8N-API-KEY': cfg.n8n_key, 'Content-Type': 'application/json' },
      body: JSON.stringify(wf)
    });

    var spawnRecord = {
      id: created.id,
      name: created.name,
      type: agent.type,
      rationale: agent.rationale,
      expected_value: agent.expected_value,
      active: false,
      created_at: new Date().toISOString()
    };

    // Auto-activate if enabled (default: off — Guardian Charter requires human approval)
    if (cfg.auto_activate === 'true' && created.id) {
      try {
        await $fetch(cfg.n8n_base + '/api/v1/workflows/' + created.id + '/activate', {
          method: 'POST',
          headers: { 'X-N8N-API-KEY': cfg.n8n_key }
        });
        spawnRecord.active = true;
      } catch(activateErr) {
        spawnRecord.activate_error = activateErr.message;
      }
    }

    // Log spawn to ledger
    try {
      await $fetch('https://evezos.app.n8n.cloud/webhook/evez-ledger', {
        method: 'POST',
        body: { event_type: 'AGENT_SPAWNED', payload: spawnRecord }
      });
    } catch(logErr) {}

    spawned.push(spawnRecord);

  } catch(e) {
    failed.push({ type: agent.type, reason: e.message });
  }
}

return [{ json: { spawned: spawned, failed: failed, total_spawned: spawned.length, ts: new Date().toISOString() } }];

const cfg = $('EVEZ Config').first().json;
const reaped = [];
const kept = [];

if (!cfg.n8n_key) {
  return [{ json: { reaped: [], kept: [], note: 'Reaper needs N8N_API_KEY to manage spawned agents', ts: new Date().toISOString() } }];
}

try {
  // List all workflows
  var allWfs = await $fetch(cfg.n8n_base + '/api/v1/workflows?limit=100', {
    headers: { 'X-N8N-API-KEY': cfg.n8n_key }
  });

  var workflows = (allWfs.data || []);
  var now = Date.now();
  var SPAWN_PREFIX = 'SPAWN:';
  var MAX_AGE_DAYS = 14;
  var MAX_AGE_MS = MAX_AGE_DAYS * 24 * 60 * 60 * 1000;

  for (var i = 0; i < workflows.length; i++) {
    var wf = workflows[i];
    if (!wf.name || !wf.name.startsWith(SPAWN_PREFIX)) continue; // Only manage spawned agents

    var age = now - new Date(wf.createdAt).getTime();
    var isOld = age > MAX_AGE_MS;
    var isInactive = !wf.active;
    var shouldReap = isOld && isInactive;

    if (shouldReap) {
      try {
        await $fetch(cfg.n8n_base + '/api/v1/workflows/' + wf.id, {
          method: 'DELETE',
          headers: { 'X-N8N-API-KEY': cfg.n8n_key }
        });
        reaped.push({ id: wf.id, name: wf.name, age_days: Math.floor(age / 86400000), reason: 'Stale: >' + MAX_AGE_DAYS + 'd inactive' });
      } catch(delErr) {
        kept.push({ id: wf.id, name: wf.name, note: 'Delete failed: ' + delErr.message });
      }
    } else {
      kept.push({ id: wf.id, name: wf.name, active: wf.active, age_days: Math.floor(age / 86400000) });
    }
  }
} catch(e) {
  return [{ json: { error: e.message, reaped: [], kept: [], ts: new Date().toISOString() } }];
}

return [{ json: { reaped: reaped, kept: kept, reaped_count: reaped.length, active_empire_count: kept.filter(function(w){ return w.active; }).length, ts: new Date().toISOString() } }];

const signals = $('Opportunity Scanner').first().json;
const architect = $('AI Architect').first().json;
const spawn = $('Spawn Engine').first().json;
const reaper = $('Reaper').first().json;
const cfg = $('EVEZ Config').first().json;

function H(d){var h=5381,s=typeof d==='string'?d:JSON.stringify(d);for(var i=0;i<s.length;i++){h=((h<<5)+h)+s.charCodeAt(i);h|=0;}return 'sha_'+Math.abs(h).toString(16).padStart(16,'0');}

// Calculate execution budget
var active_agents = reaper.active_empire_count || 0;
var spawned_today = spawn.total_spawned || 0;
var daily_execs = 4 + (active_agents * 2); // master (4/day) + spawned agents (~2/day each)
var monthly_budget = daily_execs * 30;
var free_trial_cap = 2500;
var budget_pct = Math.round(monthly_budget / free_trial_cap * 100);

var report = {
  // Empire state
  empire: {
    active_agents: active_agents,
    spawned_this_cycle: spawned_today,
    reaped_this_cycle: reaper.reaped_count || 0,
    agents_in_production: (reaper.kept || []).filter(function(w){ return w.active; }).map(function(w){ return w.name; }),
    analysis: architect.analysis || ''
  },
  // Market pulse
  market: {
    fear_greed: signals.fear_greed && signals.fear_greed.now ? signals.fear_greed.now.value + ' — ' + signals.fear_greed.now.label : 'unknown',
    trend_direction: signals.fear_greed && signals.fear_greed.trend > 0 ? 'GREED_RISING' : 'FEAR_RISING',
    top_defi: (signals.defi && signals.defi.trending ? signals.defi.trending.slice(0, 3).map(function(c){ return c.symbol; }).join(', ') : 'unavailable'),
    open_grants: (signals.grants || []).length,
    data_sources_live: signals.sources_count || 0
  },
  // Budget guardian
  budget: {
    daily_executions: daily_execs,
    monthly_projected: monthly_budget,
    free_trial_cap: free_trial_cap,
    utilization_pct: budget_pct,
    status: budget_pct < 50 ? 'HEALTHY' : budget_pct < 80 ? 'MONITOR' : 'REDUCE_AGENTS',
    note: budget_pct > 80 ? 'Reaper will prune inactive agents next cycle' : 'Budget healthy — empire can grow'
  },
  // Spawn results
  spawned: (spawn.spawned || []).map(function(a){ return { name: a.name, type: a.type, active: a.active, value: a.expected_value }; }),
  spawn_failures: spawn.failed || [],
  // Config status
  config: {
    groq: !!(cfg.groq_key || ''),
    gemini: !!(cfg.gemini_key || ''),
    openrouter: !!(cfg.or_key || ''),
    n8n_api: !!(cfg.n8n_key || ''),
    auto_activate: cfg.auto_activate,
    missing: [
      (!cfg.groq_key ? 'GROQ_API_KEY (console.groq.com — free)' : null),
      (!cfg.gemini_key ? 'GEMINI_API_KEY (aistudio.google.com — free)' : null),
      (!cfg.or_key ? 'OPENROUTER_API_KEY (openrouter.ai — free)' : null),
      (!cfg.n8n_key ? 'N8N_API_KEY (n8n Settings → API — required for spawning)' : null),
    ].filter(Boolean)
  },
  entry_hash: H('empire_' + new Date().toISOString().slice(0, 13)),
  cycle: signals.slot,
  ts: new Date().toISOString(),
  next_cycle: new Date(Date.now() + 6 * 3600000).toISOString(),
  pid: 335
};

// Log to ledger
try {
  await $fetch('https://evezos.app.n8n.cloud/webhook/evez-ledger', {
    method: 'POST',
    body: { event_type: 'EMPIRE_CYCLE', payload: report }
  });
} catch(e) {}

return [{ json: report }];

